import{_ as s,o as i,c as t,a3 as e}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"开发环境搭建","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1780241474000}'),l={name:"guide/getting-started.md"};function n(d,a,h,p,o,r){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="开发环境搭建" tabindex="-1">开发环境搭建 <a class="header-anchor" href="#开发环境搭建" aria-label="Permalink to &quot;开发环境搭建&quot;">​</a></h1><p>本篇用于快速搭好 AIO Hub 的本地开发环境。项目使用 Bun、Tauri v2、Vue 3、TypeScript 和 Rust；命令以当前仓库 <code>package.json</code> 中的 scripts 为准。</p><h2 id="前置软件" tabindex="-1">前置软件 <a class="header-anchor" href="#前置软件" aria-label="Permalink to &quot;前置软件&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">软件</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">Bun</td><td style="text-align:left;">前端包管理与脚本运行</td></tr><tr><td style="text-align:left;">Rust</td><td style="text-align:left;">Tauri 后端编译</td></tr><tr><td style="text-align:left;">Tauri CLI</td><td style="text-align:left;">启动和打包桌面应用</td></tr><tr><td style="text-align:left;">WebView2</td><td style="text-align:left;">Windows 运行 Tauri WebView</td></tr><tr><td style="text-align:left;">Android / iOS 工具链</td><td style="text-align:left;">仅移动端开发需要</td></tr></tbody></table><p>Windows 用户建议先安装 Visual Studio Build Tools，并勾选 C++ 桌面开发相关组件。</p><h2 id="获取依赖" tabindex="-1">获取依赖 <a class="header-anchor" href="#获取依赖" aria-label="Permalink to &quot;获取依赖&quot;">​</a></h2><p>在仓库根目录执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>不要改用 npm、yarn 或 pnpm。仓库锁文件和脚本均以 Bun 为准。</p><h2 id="常用命令" tabindex="-1">常用命令 <a class="header-anchor" href="#常用命令" aria-label="Permalink to &quot;常用命令&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>启动桌面端开发环境。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tauri:dev</span></span></code></pre></div><p>直接通过 Tauri 启动真实桌面窗口。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span></code></pre></div><p>启动文档开发服务器。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span></code></pre></div><p>构建并验证文档站点。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:frontend</span></span></code></pre></div><p>运行前端类型检查。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check:backend</span></span></code></pre></div><p>运行 Rust 后端检查。</p><p>完整脚本请以根目录 <code>package.json</code> 为准。</p><h2 id="桌面端调试" tabindex="-1">桌面端调试 <a class="header-anchor" href="#桌面端调试" aria-label="Permalink to &quot;桌面端调试&quot;">​</a></h2><p>涉及 Tauri API、窗口、插件、文件系统或 IPC 的功能，必须使用 Tauri 窗口验证。普通浏览器只能用于纯前端外观检查，不能代表真实运行态。</p><p>推荐流程：</p><ol><li>执行 <code>bun run tauri:dev</code>。</li><li>在 Tauri 窗口中复现功能。</li><li>打开 WebView DevTools 查看控制台和 DOM。</li><li>同时观察后端终端输出。</li></ol><h2 id="移动端开发" tabindex="-1">移动端开发 <a class="header-anchor" href="#移动端开发" aria-label="Permalink to &quot;移动端开发&quot;">​</a></h2><p>移动端代码在 <code>mobile/</code> 目录，使用独立的 Tauri 移动端配置。根目录提供快捷脚本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtad</span></span></code></pre></div><p>启动 Android 开发。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtab</span></span></code></pre></div><p>构建 Android。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtid</span></span></code></pre></div><p>启动 iOS 开发。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtib</span></span></code></pre></div><p>构建 iOS。</p><p>移动端工具链依赖 Android Studio、Xcode 和对应平台 SDK。首次配置耗时较长，建议先确认桌面端能正常启动。</p><h2 id="文档开发" tabindex="-1">文档开发 <a class="header-anchor" href="#文档开发" aria-label="Permalink to &quot;文档开发&quot;">​</a></h2><p>用户教程位于 <code>docs/user-guide/</code>，开发指南位于 <code>docs/guide/</code>，架构文档位于 <code>docs/architecture/</code>。</p><p>新增文档后记得：</p><ol><li>更新 <code>docs/.vitepress/config.ts</code> 侧边栏。</li><li>使用相对链接连接相关教程。</li><li>运行 <code>bun run docs:build</code> 检查构建。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么不能直接用浏览器打开-vite-页面验证" tabindex="-1">为什么不能直接用浏览器打开 Vite 页面验证？ <a class="header-anchor" href="#为什么不能直接用浏览器打开-vite-页面验证" aria-label="Permalink to &quot;为什么不能直接用浏览器打开 Vite 页面验证？&quot;">​</a></h3><p>普通浏览器没有 Tauri 注入的 IPC、插件和窗口运行时。只看页面布局可以用浏览器；验证真实功能必须用 Tauri 窗口。</p><h3 id="rust-编译失败怎么办" tabindex="-1">Rust 编译失败怎么办？ <a class="header-anchor" href="#rust-编译失败怎么办" aria-label="Permalink to &quot;Rust 编译失败怎么办？&quot;">​</a></h3><p>先确认 Rust 工具链、系统构建工具和平台 SDK 已安装。Windows 下重点检查 Visual Studio Build Tools，macOS 下检查 Xcode Command Line Tools。</p><h3 id="文档构建失败怎么办" tabindex="-1">文档构建失败怎么办？ <a class="header-anchor" href="#文档构建失败怎么办" aria-label="Permalink to &quot;文档构建失败怎么办？&quot;">​</a></h3><p>优先查看报错文件和行号。常见原因包括 Markdown 表格格式错误、未包裹 Vue 模板语法、链接路径错误或代码块 fence 没有闭合。</p><h3 id="应该运行完整-bun-run-check-吗" tabindex="-1">应该运行完整 <code>bun run check</code> 吗？ <a class="header-anchor" href="#应该运行完整-bun-run-check-吗" aria-label="Permalink to &quot;应该运行完整 `bun run check` 吗？&quot;">​</a></h3><p>改动范围小时可以先运行对应检查。提交前建议运行完整检查；但后端、移动端检查耗时更长，需要根据当前改动范围选择。</p>',51)])])}const k=s(l,[["render",n]]);export{u as __pageData,k as default};
